import javax.jws.WebService;
import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.xml.bind.annotation.XmlElement;
import java.util.ArrayList;
import java.util.List;

@WebService(serviceName = "OrderProcessingService")
public class OrderProcessingService {
    
    @WebMethod(operationName = "processOrder")
    public OrderResponse processOrder(@WebParam(name = "orderRequest") OrderRequest orderRequest) {
        OrderResponse response = new OrderResponse();
        
        try {
            double totalPrice = calculateTotalPrice(orderRequest.getItems());
            response.setOrderId(orderRequest.getOrderId());
            response.setTotalPrice(totalPrice);
            response.setStatus("SUCCESS");
            response.setMessage("Order processed successfully");
        } catch (Exception e) {
            response.setStatus("ERROR");
            response.setMessage("Failed to process order: " + e.getMessage());
        }
        
        return response;
    }
    
    private double calculateTotalPrice(List<OrderItem> items) {
        double total = 0.0;
        for (OrderItem item : items) {
            total += item.getPrice() * item.getQuantity();
        }
        return total;
    }
}

